		public static ReadOnlySpan<float> Mos8580PostWrite => Mos8580PostWriteData;

		public static float GetMos6581PreWrite(int previousRegisterValue, int nextRegisterValue)
		{
			return Mos6581PreWriteData[Index(previousRegisterValue, nextRegisterValue)];
		}

		public static float GetMos6581PostWrite(int previousRegisterValue, int nextRegisterValue)
		{
			return Mos6581PostWriteData[Index(previousRegisterValue, nextRegisterValue)];
		}

		public static float GetMos8580PreWrite(int previousRegisterValue, int nextRegisterValue)
		{
			return Mos8580PreWriteData[Index(previousRegisterValue, nextRegisterValue)];
		}

		public static float GetMos8580PostWrite(int previousRegisterValue, int nextRegisterValue)
		{
			return Mos8580PostWriteData[Index(previousRegisterValue, nextRegisterValue)];
		}

		private static int Index(int previousRegisterValue, int nextRegisterValue)
		{
			return ((previousRegisterValue & 0xFF) << 8) | (nextRegisterValue & 0xFF);
		}
